SELECT ?team ?teamLabel WHERE {
  ?team p:P286 [
    ps:P286 wd:Q2844569 ;
    pq:P582 ?endTime
  ].
  OPTIONAL {
    ?team rdfs:label ?teamLabel .
    FILTER(LANG(?teamLabel) = "en")
  }
}
ORDER BY DESC(?endTime)
LIMIT 1

